  ('judicial-57112235-moex-00057', 'judicial-57112235', 'judicial-57112235-moex-114-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '下列那位學者提出的理論，將犯罪行為解釋為「下階層文化」對環境的自然反應，並認為下階層 文化本身就含有犯罪要素？', '["涂爾幹（Durkheim）", "墨爾頓（Merton）", "米勒（Miller）", "雪林（Sellin） 20650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "8d340db50acd", "answer_pdf_sha1": "c5c4535714d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00058', 'judicial-57112235', 'judicial-57112235-moex-114-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '社會衝突學派的「衝突觀」認為，法律的本質為何？', '["法律為社會整體一致譴責行為的共識體現", "法律是權勢者用以保障自身利益的工具", "法律是人們為了維護社會秩序而自願制定的規範", "法律是超越階層、種族或性別區別的普世道德準則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "8d340db50acd", "answer_pdf_sha1": "c5c4535714d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00059', 'judicial-57112235', 'judicial-57112235-moex-114-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '依據李瑪特（Lemert）及貝克（Becker）所提出之標籤理論（LabelingTheory），下列何者是導致 「第二階段偏差行為」（SecondaryDeviance）形成的主要原因？', '["個體對犯罪行為的理性選擇", "缺乏社會支持網絡而產生的疏離感", "家庭功能失調導致的自我控制不足", "社會對第一階段偏差行為的嚴重非難與標籤化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "8d340db50acd", "answer_pdf_sha1": "c5c4535714d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00060', 'judicial-57112235', 'judicial-57112235-moex-114-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '下列關於「白領犯罪」特徵的敘述，何者錯誤？', '["犯罪方式多以合法活動掩飾非法及濫用誠信原則", "社會大眾對白領犯罪的「非價領悟」通常較高，認為其違背正義而應加以譴責的感受程度較高", "因為犯罪人的特殊背景與性質、涉及的損害層面較廣、犯罪涉及專業知識，因此要追訴白領犯 罪較為困難", "受害人薄弱反應，不願求助刑事司法機關的情況較為常見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "8d340db50acd", "answer_pdf_sha1": "c5c4535714d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00061', 'judicial-57112235', 'judicial-57112235-moex-114-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '學者Groth（1979）對強制性交犯進行臨床觀察後，將強制性交犯罪人進行分類。以下何者「不」 是Groth（1979）所區分的類型？', '["性攻擊放射型（Sex-Aggression-DiffusionRapist）", "權力型（ThePowerRapist）", "憤怒型（TheAngerRapist）", "虐待型（SadisticRapist）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "8d340db50acd", "answer_pdf_sha1": "c5c4535714d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
